CodeInjections.CodeInjection:
#if defined(ALBEDO_MAP)
    float2 uv = getDefaultTexCoords(In);
    float2 uv1 = uv + directions.xy * cTime_s;
    float2 uv2 = uv+float2(0.5, 0.2) + directions.zw * cTime_s;
    Out.defaultTexCoords = uv1;
    Out.defaultTexCoords2 = uv2;
#endif

#if defined(ALBEDO_MAP)
    float4 diffuseColor2 = tex2D(baseMap, In.vs.defaultTexCoords2);
    diffuseColor.xyz = lerp(diffuseColor.xyz, diffuseColor2.xyz, diffuseColor2.w);
    //diffuseColor.w = max(diffuseColor.w, diffuseColor2.w);    // there is no diffuseColor.w
#endif
